CHUNK_SIZE = 800  # chars per drawer
CHUNK_OVERLAP = 100  # overlap between chunks
MIN_CHUNK_SIZE = 50  # skip tiny chunks
MAX_FILE_SIZE = 10 * 1024 * 1024  # 10 MB — skip files larger than this

# Heuristic thresholds
LONGEST_LINE_REJECT = 500  # unconditional reject if any line longer than this
WHITESPACE_RATIO_THRESHOLD = 0.05
AVG_LINE_LENGTH_THRESHOLD = 200
SYMBOL_TO_ALNUM_RATIO_THRESHOLD = 1.5

# Generated file signatures (small subset inspired by GitHub Linguist)
_HEADER_GENERATED_SIGNATURES = re.compile(
    r"(?im)^(?:\s*(?://|#|/\*+|\*)\s*)?(?:<auto-generated>|code generated by\b|@generated\b)"
)
_LICENSE_BANNER_SIGNATURE = re.compile(
    r"(?im)^\s*/\*![^\n]*for license information please see[^\n]*$"
)
_HEAD_TAIL_GENERATED_SIGNATURES = re.compile(r"(?i)sourceMappingURL=|webpackJsonp")

_MINIFIED_FILENAME_PATTERNS = (".min.js", ".min.css", ".bundle.js", ".map")


def _longest_line_length(content: str) -> int:
    return max((len(line) for line in content.splitlines()), default=0)


def _whitespace_ratio(content: str) -> float:
    if not content:
        return 1.0
    whitespace_chars = sum(1 for c in content if c.isspace())
    return whitespace_chars / len(content)


def _avg_line_length(content: str) -> float:
    lines = content.splitlines()
    if not lines:
        return 0.0
    return sum(len(line) for line in lines) / len(lines)


def _symbol_to_alnum_ratio(content: str) -> float:
    # ratio of symbol chars to alphanumeric chars
    alnum = sum(1 for c in content if c.isalnum())
    symbol = sum(1 for c in content if not c.isalnum() and not c.isspace())
    if alnum == 0:
        return float("inf") if symbol > 0 else 0.0
    return symbol / alnum


def _mining_rejection_reason(filepath: Path, content: str) -> str | None:
    """Return rejection reason when file looks too generated/dense to mine."""
    if content is None:
        return None

    longest_line = _longest_line_length(content)
    if longest_line > LONGEST_LINE_REJECT:
        return f"longest line {longest_line} > {LONGEST_LINE_REJECT}"

    name = filepath.name.lower()
    suffix = filepath.suffix.lower()

    for pat in _MINIFIED_FILENAME_PATTERNS:
        if name.endswith(pat):
            return f"filename matches {pat}"

    header = "\n".join(content.splitlines()[:3])
    head_tail = (content[:1000] + content[-1000:]) if len(content) > 2000 else content
    if _HEADER_GENERATED_SIGNATURES.search(header):
        return "generated header signature"
    if _LICENSE_BANNER_SIGNATURE.search(header):
        return "bundler license banner"
    if _HEAD_TAIL_GENERATED_SIGNATURES.search(head_tail):
        return "bundler/source map signature"

    if suffix == ".json":
        return None

    ws_ratio = _whitespace_ratio(content)
    if ws_ratio < WHITESPACE_RATIO_THRESHOLD:
        return f"whitespace ratio {ws_ratio:.3f} < {WHITESPACE_RATIO_THRESHOLD}"

    avg_line_length = _avg_line_length(content)
    if avg_line_length > AVG_LINE_LENGTH_THRESHOLD:
        return f"average line length {avg_line_length:.1f} > {AVG_LINE_LENGTH_THRESHOLD}"

    symbol_ratio = _symbol_to_alnum_ratio(content)
    if symbol_ratio > SYMBOL_TO_ALNUM_RATIO_THRESHOLD:
        return f"symbol/alnum ratio {symbol_ratio:.2f} > {SYMBOL_TO_ALNUM_RATIO_THRESHOLD}"

    return None


def is_probably_minified(filepath: Path, content: str) -> bool:
    """Return True when file looks minified/generated and should be skipped."""
    return _mining_rejection_reason(filepath, content) is not None


# =============================================================================
# IGNORE MATCHING
# =============================================================================


class GitignoreMatcher:
    """Lightweight matcher for one directory's .gitignore-like patterns."""

    def __init__(self, base_dir: Path, rules: list):
        self.base_dir = base_dir
        self.rules = rules

    @classmethod
    def _from_file(cls, dir_path: Path, filename: str):
        path = dir_path / filename
        if not path.is_file():
            return None

        try:
            lines = path.read_text(encoding="utf-8", errors="replace").splitlines()
        except Exception:
            return None

        rules = []
        for raw_line in lines:
            line = raw_line.strip()
            if not line:
                continue

            if line.startswith("\\#") or line.startswith("\\!"):
                line = line[1:]
            elif line.startswith("#"):
                continue

            negated = line.startswith("!")
            if negated:
                line = line[1:]

            anchored = line.startswith("/")
            if anchored:
                line = line.lstrip("/")

            dir_only = line.endswith("/")
            if dir_only:
                line = line.rstrip("/")

            if not line:
                continue

            rules.append(
                {
                    "pattern": line,
                    "anchored": anchored,
                    "dir_only": dir_only,
                    "negated": negated,
                }
            )

        if not rules:
            return None

        return cls(dir_path, rules)

    @classmethod
    def from_dir(cls, dir_path: Path):
        return cls._from_file(dir_path, ".gitignore")

    @classmethod
    def from_swampignore(cls, dir_path: Path):
        """Load .swampcastleignore (project-specific mining ignore)."""
        return cls._from_file(dir_path, ".swampcastleignore")

    def matches(self, path: Path, is_dir: bool = None):
        try:
            relative = path.relative_to(self.base_dir).as_posix().strip("/")
        except ValueError:
            return None

        if not relative:
            return None

        if is_dir is None:
            is_dir = path.is_dir()

        ignored = None
        for rule in self.rules:
            if self._rule_matches(rule, relative, is_dir):
                ignored = not rule["negated"]
        return ignored

    def _rule_matches(self, rule: dict, relative: str, is_dir: bool) -> bool:
        pattern = rule["pattern"]
        parts = relative.split("/")
        pattern_parts = pattern.split("/")

        if rule["dir_only"]:
            target_parts = parts if is_dir else parts[:-1]
            if not target_parts:
                return False
            if rule["anchored"] or len(pattern_parts) > 1:
                return self._match_from_root(target_parts, pattern_parts)
            return any(fnmatch.fnmatch(part, pattern) for part in target_parts)

        if rule["anchored"] or len(pattern_parts) > 1:
            return self._match_from_root(parts, pattern_parts)

        return any(fnmatch.fnmatch(part, pattern) for part in parts)

    def _match_from_root(self, target_parts: list, pattern_parts: list) -> bool:
        def matches(path_index: int, pattern_index: int) -> bool:
            if pattern_index == len(pattern_parts):
                return True

            if path_index == len(target_parts):
                return all(part == "**" for part in pattern_parts[pattern_index:])

            pattern_part = pattern_parts[pattern_index]
            if pattern_part == "**":
                return matches(path_index, pattern_index + 1) or matches(
                    path_index + 1, pattern_index
                )

            if not fnmatch.fnmatch(target_parts[path_index], pattern_part):
                return False

            return matches(path_index + 1, pattern_index + 1)

        return matches(0, 0)


def load_gitignore_matcher(dir_path: Path, cache: dict):
    """Load and cache one directory's .gitignore matcher."""
    if dir_path not in cache:
        cache[dir_path] = GitignoreMatcher.from_dir(dir_path)
    return cache[dir_path]


def load_swampignore_matcher(dir_path: Path, cache: dict):
    """Load and cache one directory's .swampcastleignore matcher."""
    if dir_path not in cache:
        cache[dir_path] = GitignoreMatcher.from_swampignore(dir_path)
    return cache[dir_path]


def _ignore_decision(path: Path, matchers: list, is_dir: bool = False) -> bool | None:
    """Return the last ignore decision for a path, or None when no rule matched."""
    decision = None
    for matcher in matchers:
        matched = matcher.matches(path, is_dir=is_dir)
        if matched is not None:
            decision = matched
    return decision


def is_gitignored(path: Path, matchers: list, is_dir: bool = False) -> bool:
    """Apply active .gitignore matchers in ancestor order; last match wins."""
    return _ignore_decision(path, matchers, is_dir=is_dir) is True


def is_swampignored(path: Path, matchers: list, is_dir: bool = False) -> bool:
    """Apply active .swampcastleignore matchers in ancestor order; last match wins."""
    return _ignore_decision(path, matchers, is_dir=is_dir) is True


def should_skip_dir(dirname: str) -> bool:
    """Skip known generated/cache directories before gitignore matching."""
    return dirname in SKIP_DIRS or dirname.endswith(".egg-info")


def normalize_include_paths(include_ignored: list) -> set:
    """Normalize comma-parsed include paths into project-relative POSIX strings."""
    normalized = set()
    for raw_path in include_ignored or []:
        candidate = str(raw_path).strip().strip("/")
        if candidate:
            normalized.add(Path(candidate).as_posix())
    return normalized


def is_exact_force_include(path: Path, project_path: Path, include_paths: set) -> bool:
    """Return True when a path exactly matches an explicit include override."""
    if not include_paths:
        return False

    try:
        relative = path.relative_to(project_path).as_posix().strip("/")
    except ValueError:
        return False

    return relative in include_paths


def is_force_included(path: Path, project_path: Path, include_paths: set) -> bool:
    """Return True when a path or one of its ancestors/descendants was explicitly included."""
    if not include_paths:
        return False

    try:
        relative = path.relative_to(project_path).as_posix().strip("/")
    except ValueError:
        return False

    if not relative:
        return False

    for include_path in include_paths:
        if relative == include_path:
            return True
        if relative.startswith(f"{include_path}/"):
            return True
        if include_path.startswith(f"{relative}/"):
            return True

    return False


